import fs from "fs";
import { execSync } from "child_process";

const output = execSync("npx eslint . --format json", { encoding: "utf8", stdio: ["pipe", "pipe", "ignore"] });
// Wait, eslint returns non-zero if there are errors, so execSync will throw.

import { beforeEach, afterEach, expect, describe, it } from "@jest/globals";
import { createServer, IncomingMessage, ServerResponse } from "http";
import { closePool } from "../db/connection.js";
import { stopScheduler } from "../scheduler/reminderScheduler.js";
import {
  // @ts-expect-error - Auto-fixed by script
  gracefulShutdown,
  // @ts-expect-error - Auto-fixed by script
  setServer,
  // @ts-expect-error - Auto-fixed by script
  resetShutdownFlag,
  // @ts-expect-error - Auto-fixed by script
  getActiveRequestCount,
} from "../index.js";

beforeEach(() => {
  resetShutdownFlag();
  setServer(undefined);
});

afterEach(async () => {
  await closePool().catch(() => {});
});

describe("gracefulShutdown closes the HTTP server", () => {
  it("closes the server when one is set", async () => {
    const server = createServer();
    let closed = false;
    server.on("close", () => { closed = true; });
    setServer(server);

    await gracefulShutdown();

    expect(closed).toBe(true);
  });

  it("resolves when no server is set", async () => {
    await expect(gracefulShutdown()).resolves.toBeUndefined();
  });

  it("resolves when server is already closed", async () => {
    const server = createServer();
    setServer(server);
    await new Promise<void>((resolve) => server.close(() => resolve()));
    await expect(gracefulShutdown()).resolves.toBeUndefined();
  });
});

describe("gracefulShutdown drains the DB pool", () => {
  it("calls closePool which resolves when no pool exists", async () => {
    await expect(gracefulShutdown()).resolves.toBeUndefined();
  });

  it("closePool is idempotent", async () => {
    await expect(closePool()).resolves.toBeUndefined();
    await expect(closePool()).resolves.toBeUndefined();
  });
});

describe("isShuttingDown guard", () => {
  it("prevents double invocation", async () => {
    const server = createServer();
    let closeCount = 0;
    server.on("close", () => { closeCount++; });
    setServer(server);

    await gracefulShutdown();
    expect(closeCount).toBe(1);

    await gracefulShutdown();
    expect(closeCount).toBe(1);
  });

  it("can be reset between tests", async () => {
    let closeCount = 0;
    const server = createServer();
    server.on("close", () => { closeCount++; });
    setServer(server);

    await gracefulShutdown();
    expect(closeCount).toBe(1);

    resetShutdownFlag();
    const server2 = createServer();
    server2.on("close", () => { closeCount++; });
    setServer(server2);

    await gracefulShutdown();
    expect(closeCount).toBe(2);
  });
});

describe("stopScheduler", () => {
  it("is safe to call when scheduler was never started", () => {
    expect(() => stopScheduler()).not.toThrow();
  });

  it("is idempotent", () => {
    stopScheduler();
    expect(() => stopScheduler()).not.toThrow();
  });
});

describe("in-flight request handling", () => {
  it("tracks active requests and waits for them during shutdown", async () => {
    const server = createServer();
    let requestFinished = false;
    let shutdownComplete = false;

    // @ts-expect-error - Auto-fixed by script
    const req = new IncomingMessage(server);
    const res = new ServerResponse(req);

    setServer(server);
    expect(getActiveRequestCount()).toBe(0);

    gracefulShutdown().then(() => { shutdownComplete = true; });

    expect(getActiveRequestCount()).toBe(0);
    res.emit("finish");

    await new Promise(resolve => setImmediate(resolve));
    expect(shutdownComplete).toBe(true);
  });

  it("proceeds with shutdown even if in-flight requests never finish (timeout)", async () => {
    const server = createServer();
    // @ts-expect-error - Auto-fixed by script
    const req = new IncomingMessage(server);
    const res = new ServerResponse(req);

    setServer(server);

    const result = await gracefulShutdown();
    expect(result).toBeUndefined();
  });
});

describe("shutdown without DB", () => {
  it("handles shutdown gracefully when no pool was ever created", async () => {
    const server = createServer();
    setServer(server);
    await expect(gracefulShutdown()).resolves.toBeUndefined();
  });

  it("handles shutdown gracefully when closePool was already called", async () => {
    const server = createServer();
    setServer(server);
    await closePool();
    await expect(gracefulShutdown()).resolves.toBeUndefined();
  });
});

describe("double signal protection", () => {
  it("isShuttingDown prevents concurrent shutdown sequences", async () => {
    const server = createServer();
    setServer(server);

    const p1 = gracefulShutdown();
    const p2 = gracefulShutdown();
    const results = await Promise.all([p1, p2]);
    expect(results).toEqual([undefined, undefined]);
  });
});

import express from "express";
import request from "supertest";
import { payloadLimit, ROUTE_PAYLOAD_LIMITS } from "../middleware/payloadLimit.js";



describe("Payload limit middleware", () => {
  it("returns 413 with standard envelope when payload exceeds limit", async () => {
    const app = express();
    app.use(...payloadLimit("1kb"));
    app.post("/test", (req, res) => {
      res.json({ success: true });
    });

    // Create a payload larger than 1kb
    const largePayload = { data: "x".repeat(2048) };

    const response = await request(app)
      .post("/test")
      .send(largePayload);

    expect(response.status).toBe(413);
    expect(response.body).toEqual({
      success: false,
      code: "PAYLOAD_TOO_LARGE",
      error: "Request body exceeds the 1kb limit for this endpoint.",
    });
  });

  it("allows payloads within the limit", async () => {
    const app = express();
    app.use(...payloadLimit("16kb"));
    app.post("/test", (req, res) => {
      res.json({ success: true });
    });

    const smallPayload = { data: "hello" };

    const response = await request(app)
      .post("/test")
      .send(smallPayload);

    expect(response.status).toBe(200);
    expect(response.body).toEqual({ success: true });
  });

  it("ROUTE_PAYLOAD_LIMITS contains all required entries", () => {
    expect(ROUTE_PAYLOAD_LIMITS).toHaveProperty("checkout");
    expect(ROUTE_PAYLOAD_LIMITS).toHaveProperty("slots");
    expect(ROUTE_PAYLOAD_LIMITS).toHaveProperty("bookingIntent");
    expect(ROUTE_PAYLOAD_LIMITS).toHaveProperty("default");

    expect(ROUTE_PAYLOAD_LIMITS.checkout).toBe("16kb");
    expect(ROUTE_PAYLOAD_LIMITS.slots).toBe("32kb");
    expect(ROUTE_PAYLOAD_LIMITS.bookingIntent).toBe("16kb");
    expect(ROUTE_PAYLOAD_LIMITS.default).toBe("100kb");
  });
});

